#include <stdio.h>
#include "riscv_nn_activation.h"
#include "test_util.h"
#ifdef PF_COUNTER
#include "nds_pfcounter.h"
#endif
#ifdef ENA_VERIFY_CMSIS_NN_WRAPPER
#include "convert_between_andes_nn_and_cmsis_nn.h"
#endif

int test(char* fname_inOut,
        char* fname_golden,
        uint32_t size)
{
    {
        dump_param("size=%" PRIu32, size);
    }

    FILE *fptr_in_out, *fptr_golden;
    //backup originally malloced starting address for later memory releasing
    void *in_out_ori, *golden_ori;

    q7_t *in_out = (q7_t*)test_malloc(sizeof(q7_t) * size, "in_out", &in_out_ori);
    q7_t *golden = (q7_t*)test_malloc(sizeof(q7_t) * size, "golden", &golden_ori);

    test_Fopen(fname_inOut, "rb", &fptr_in_out);
    test_Fread(in_out, sizeof(*in_out), size, fptr_in_out, "in_out");
    process_after_reading_input_data();

#ifdef ENA_RUN_TWICE
    riscv_nn_relu_s8(in_out, size);
#endif

    process_before_perf_measuring();
#ifdef PF_COUNTER
    startPFM;
#endif
    riscv_nn_relu_s8(in_out, size);
#ifdef PF_COUNTER
    stopPFM;
    readResult();
#endif

#if ENA_DUMP_GOLDEN
    test_Fopen(fname_golden, "wb+", &fptr_golden);
    fwrite(in_out, sizeof(*golden), size, fptr_golden);
    uint32_t retStatus = NDS_SUCCESS;
#else
    test_Fopen(fname_golden, "rb", &fptr_golden);
    test_Fread(golden, sizeof(*golden), size, fptr_golden, "golden");
    uint32_t retStatus = verify_buffer(in_out, golden, size, sizeof(*in_out), 0);
#endif

    test_free(&in_out_ori);
    test_free(&golden_ori);
    fclose(fptr_in_out);
    fclose(fptr_golden);

    return retStatus;
}

int main (void)
{
    enable_fs_and_vs();
    uint32_t size;
    uint32_t retStatus=NDS_SUCCESS;

#if !ENA_MEASURE_PERF
    //test-1: column length less than VLEN
    size = 3;
    retStatus |= test("8b_in1.bin", "relu_q7_golden.bin", size);

    //test-2: column length more than VLEN
    size = 71;
    retStatus |= test("8b_in1.bin", "relu_q7_golden2.bin", size);
#endif

    //test-3: max column length
    size = 65535;
    retStatus |= test("8b_in1.bin", "relu_q7_golden3.bin", size);

    return retStatus;
}

