      platform.int_trigger.write(1);
      ctx_resuming = false;
      ctx_triggered = true;
    }

    sc_core::sc_start(platform.clk.period());

    trace_.on_cycle(cpu);

    if (context_config.save_on_wfi && platform.wfi_signal.read() == true)
      [[unlikely]]
    {
      context_config.save(platform, cpu);
      spdlog::info("User save context");
      return 0;
    }

    if (ctrlc != 0) {
      ctrlc = 0;
      spdlog::info("Ctrl+C PC: {:x}", get_current_pc());
      trace_.log_committed_pcs(cpu);
      return 130;
    }

    if (ctx_triggered) [[unlikely]] {
      // Pull down the interrupt signal after 1 cycle
      platform.int_trigger.write(0);
      ctx_triggered = false;
    }

    if (platform.sim_control.exits >= 0) {
      spdlog::info("sim_control: got exit {}, stopping",
                   platform.sim_control.exits);
      spdlog::info("Exit PC: {:x}", get_current_pc());
      trace_.log_committed_pcs(cpu);
      return platform.sim_control.exits;
    }

    if (this->cpu.contextp()->gotFinish())
      return 0;

    spdlog::trace("PC: {:x}", get_current_pc());
  }
  return 0;
}

uint64_t get_current_pc()
{
  if constexpr (requires { cpu.get_current_pc(); }) {
    return cpu.get_current_pc();
  }
  return std::numeric_limits<uint64_t>::max();
}

