113	/// One pipeline slot (issue lane) configuration.
114	using PipeSlotConfig = std::vector<SignalRule>;
115	
116	// ── VPU types ────────────────────────────────────────────────────────────
117	
118	enum class VectorFU
119	{
120	  VALU = 0,
121	  VLSU,
122	  VSP,
123	  VMAC,
124	  VDIV,
125	  VFMIS,
126	  VPERMUT,
127	  VFDIV,
128	  VMASK,
129	  VACE,
130	  VMAC2,
131	  COUNT_
132	};
133	
134	constexpr std::array<std::string_view, static_cast<int>(VectorFU::COUNT_)>
135	  kVfuNames = {
136	    "valu",    "vlsu",  "vsp",   "vmac", "vdiv",  "vfmis",
137	    "vpermut", "vfdiv", "vmask", "vace", "vmac2",
138	};
