145	struct VpuConfig
146	{
147	  bool dual_vlsu_ports = false;
148	  bool has_vd_x4 = false;
149	  bool countdown_vw_labels = true;
150	};
151	
152	// ── Pipeline configuration ───────────────────────────────────────────────
153	
154	/// Full pipeline configuration: stage names, per-slot signal rules, last stage
155	/// name.
156	struct PipelineConfig
157	{
158	  std::vector<std::string> stage_names;
159	  std::vector<PipeSlotConfig> slots;
160	  std::string last_stage_name; // for end_stage_insn on retire
161	  std::optional<VpuConfig> vpu = std::nullopt;
162	};
163	
164	// Forward declare so PipelineModeler can hold a pointer.
165	template<typename CPU>
166	class VpuPipelineModeler;
167	
168	/// Records pipeline events each cycle using CPU signals.
169	/// Port of Python PipelineModeler from tools/andes45.py.
170	template<typename CPU>
171	class PipelineModeler
172	{
173	public:
174	  PipelineModeler(CPU& cpu, KanataLogger& kanata, PipelineConfig config)
175	      : cpu_(cpu), kanata_(kanata), config_(std::move(config))
176	  {
177	    auto num_stages = static_cast<int>(config_.stage_names.size());
178	    for (size_t i = 0; i < config_.slots.size(); ++i)
179	      pipes_.emplace_back(num_stages, id_map_);
180	  }
181	
182	  void set_vpu(VpuPipelineModeler<CPU>* vpu) { vpu_ = vpu; }
183	
184	  /// Call once per cycle to record pipeline events.
185	  void record()
186	  {
187	    std::vector<uint64_t> retire_ids;
188	
189	    // Find the EX stage index (for VPU enqueue)
190	    int ex_stage_idx = -1;
191	    if (vpu_) {
192	      for (size_t i = 0; i < config_.stage_names.size(); ++i) {
193	        if (config_.stage_names[i] == "EX") {
194	          ex_stage_idx = static_cast<int>(i);
195	          break;
196	        }
197	      }
198	    }
199	
200	    for (size_t slot = 0; slot < config_.slots.size(); ++slot) {
201	      auto& rules = config_.slots[slot];
202	      auto& pipe = pipes_[slot];
203	
204	      // Collect per-stage PCs
205	      std::vector<std::optional<uint64_t>> stages_pc;
206	      stages_pc.reserve(rules.size());
207	
208	      for (auto& rule: rules) {
209	        auto cond = cpu_.get_signal(rule.cond_signal);
210	        if (cond)
211	          stages_pc.push_back(cpu_.get_signal(rule.pc_signal));
212	        else
213	          stages_pc.push_back(std::nullopt);
214	      }
215	
216	      auto res = pipe.update(stages_pc);
217	
218	      if (res.retire)
219	        retire_ids.push_back(res.retire->id);
220	
221	      // Start a new stage
222	      for (size_t st = 0; st < config_.stage_names.size(); ++st) {
223	        auto& pcid = res.stage_start[st];
224	        if (!pcid)
225	          continue;
226	        if (st == 0)
227	          start_insn(*pcid);
228	        kanata_.stage_insn(pcid->id, config_.stage_names[st]);
229	
230	        if (vpu_ && static_cast<int>(st) == ex_stage_idx)
231	          vpu_->viq_enqueue_ix(static_cast<int>(slot), *pcid);
232	      }
233	
234	      // End an old stage (killed)
235	      for (size_t st = 0; st < config_.stage_names.size(); ++st) {
236	        auto& pcid = res.stage_end[st];
237	        if (!pcid)
238	          continue;
239	        kanata_.end_stage_insn(pcid->id, config_.stage_names[st]);
240	        kanata_.flush_insn(pcid->id);
241	      }
242	    }
243	
244	    // VPU pipeline record (before scalar retire, matching Python order)
245	    if (vpu_)
246	      vpu_->record();
247	
248	    // Retire in sorted order
249	    std::sort(retire_ids.begin(), retire_ids.end());
250	    for (auto id: retire_ids) {
251	      kanata_.end_stage_insn(id, config_.last_stage_name);
252	      end_insn(id);
253	    }
254	  }
255	
256	  bool has_insn_id(uint64_t id) const { return insn_ids_.count(id) != 0; }
257	
258	private:
259	  void start_insn(const PcId& pcid)
260	  {
261	    kanata_.start_insn(pcid.pc, pcid.id);
262	    insn_ids_.insert(pcid.id);
263	  }
264	
265	  void end_insn(uint64_t id)
266	  {
267	    insn_ids_.erase(id);
268	    if (!vpu_ || !vpu_->has_insn_id(id))
269	      kanata_.retire_insn(id);
270	  }
271	
272	  CPU& cpu_;
273	  KanataLogger& kanata_;
274	  PipelineConfig config_;
275	  SequentialIndexMap id_map_;
276	  std::vector<InorderPipe> pipes_;
277	  std::unordered_set<uint64_t> insn_ids_;
278	  VpuPipelineModeler<CPU>* vpu_ = nullptr;
279	};
280	
281	// ── VPU Pipeline Modeler ─────────────────────────────────────────────────
282	
283	/// Decodes the VLMUL field from VTYPE register.
284	/// Returns lmul as a float (fractional LMUL supported).
285	inline double decode_vlmul(uint64_t vtype)
286	{
287	  static constexpr double table[] = {
288	    1.0, 2.0, 4.0, 8.0, /*reserved*/ 1.0, 0.125, 0.25, 0.5,
289	  };
290	  return table[vtype & 0x7];
291	}
292	
293	/// Decodes the VSEW field from VTYPE register.
294	inline int decode_vsew(uint64_t vtype)
295	{
296	  static constexpr int table[] = {8, 16, 32, 64};
297	  return table[(vtype >> 3) & 0x3];
298	}
299	
300	/// Port of Python VPUPipelineModeler.
301	// FIXME: The pipeline is not accurate right now, too many corner cases
302	//        haven't been considered yet. Below are known issues:
303	//        XXX_vd_wvalid is pulled to 1 for discrete EMUL cycles, and we
304	//        want to draw VW stages for EMUL times.
305	//        Therefore, we have to identify all widening and narrowing
306	//        instructions to calculate the EMUL, which hasn't been done yet.
307	//        Besides, some RVV instructions always writes to single VRF,
308	//        independent of LMUL.
309	template<typename CPU>
310	class VpuPipelineModeler
311	{
312	  struct VpuReq
313	  {
314	    VectorFU fu;
315	    PcId pcid;
316	    uint32_t instr = 0;
317	    int lmul = 0;
318	    int sew = 0;
319	    int write_number = 0;
320	    int left_write_number = 0;
321	  };
322	
323	public:
324	  VpuPipelineModeler(CPU& cpu,
325	                     KanataLogger& kanata,
326	                     PipelineModeler<CPU>& scalar,
327	                     VpuConfig config)
328	      : cpu_(cpu), kanata_(kanata), scalar_(scalar), config_(config)
329	  {}
330	
331	  void viq_enqueue_ix(int slot, const PcId& pcid)
332	  {
333	    auto vpu_req_valid = cpu_.get_signal("vpu_req_valid");
334	    if (!(vpu_req_valid & (1u << slot)))
335	      return;
336	
337	    auto fu_sig = fmt::format("vpu_req_i{}_fu", slot);
338	    auto fu = parse_vpu_fu(cpu_.get_signal(fu_sig));
339	
340	    kanata_.stage_insn(pcid.id, "VQ", VPU_LANE_ID);
341	    kanata_.comment_insn(pcid.id, vfu_name(fu));
342	
343	    auto instr_sig = fmt::format("viq_i{}_instr", slot);
344	    uint32_t instr = static_cast<uint32_t>(cpu_.get_signal(instr_sig));
345	
346	    request_q_.push_back(VpuReq{fu, pcid, instr, 0, 0, 0, 0});
347	    start_insn(pcid, instr);
348	  }
349	
350	  void record()
351	  {
352	    fu_retired();
353	    fu_wvalid();
354	    fu_commit();
355	    fu_dispatch();
356	  }
357	
358	  bool has_insn_id(uint64_t id) const { return insn_ids_.count(id) != 0; }
359	
360	private:
361	  void start_insn(const PcId& pcid, uint32_t instr)
362	  {
363	    insn_ids_.insert(pcid.id);
364	    if (decode_write_number_not_zero(instr))
365	      write_port_ids_.insert(pcid.id);
366	  }
367	
368	  static VectorFU parse_vpu_fu(uint64_t signal)
369	  {
370	    for (int i = 0; i < static_cast<int>(VectorFU::COUNT_); ++i) {
371	      if (signal & 1u)
372	        return static_cast<VectorFU>(i);
373	      signal >>= 1;
374	    }
375	    spdlog::warn("VPU: unrecognized FU signal {:#x}", signal);
376	    return VectorFU::VALU;
377	  }
378	
379	  static bool decode_write_number_not_zero(uint32_t instr)
380	  {
381	    uint32_t opcode = instr & 0x7F;
382	    if (opcode == 0b0100111) // OP_STORE
383	      return false;
384	    return true;
385	  }
386	
387	  int decode_write_number(int slot, VpuReq& rq)
388	  {
389	    if (!decode_write_number_not_zero(rq.instr))
390	      return 0;
391	
392	    auto vd_wen_sig = fmt::format("i{}_instr_vd_wen", slot);
393	    auto rd_wen_sig = fmt::format("i{}_rd1_wen", slot);
394	    auto vd_x2_sig = fmt::format("i{}_vd_x2", slot);
395	    auto whole_vd_sig = fmt::format("i{}_write_whole_vd", slot);
396	    auto vd_emul_sig = fmt::format("i{}_vlsu_vd_emul", slot);
397	
398	    auto vd_wen = cpu_.get_signal(vd_wen_sig);
399	    auto rd_wen = cpu_.get_signal(rd_wen_sig);
400	    auto is_wide = cpu_.get_signal(vd_x2_sig);
401	    auto is_whole_vd = cpu_.get_signal(whole_vd_sig);
402	    auto vd_emul = cpu_.get_signal(vd_emul_sig);
403	
404	    if (rd_wen)
405	      return 1;
406	    if (!vd_wen)
407	      return 0;
408	
409	    if (is_whole_vd) {
410	      auto n_sig = fmt::format("i{}_whole_vd_num", slot);
411	      return static_cast<int>(cpu_.get_signal(n_sig));
412	    }
413	    if (rq.fu == VectorFU::VLSU)
414	      return 1 << static_cast<int>(vd_emul);
415	    if (is_wide)
416	      return std::max(1, rq.lmul * 2);
417	
418	    if (config_.has_vd_x4) {
419	      auto vd_x4_sig = fmt::format("i{}_vd_x4", slot);
420	      if (cpu_.get_signal(vd_x4_sig))
421	        return std::max(1, rq.lmul * 4);
422	    }
423	
424	    return rq.lmul;
425	  }
426	
427	  void fu_dispatch()
428	  {
429	    auto do_dispatch = [&](int slot) {
430	      if (request_q_.empty())
431	        return;
432	      auto rq = request_q_.front();
433	      request_q_.pop_front();
434	      dispatch_q_.push_back(rq);
435	
436	      kanata_.stage_insn(rq.pcid.id, "VD", VPU_LANE_ID);
437	
438	      auto vtype_sig = fmt::format("i{}_vtype", slot);
439	      auto vtype = cpu_.get_signal(vtype_sig);
440	      auto lmul_f = decode_vlmul(vtype);
441	      rq.lmul = std::max(1, static_cast<int>(lmul_f));
442	      rq.sew = decode_vsew(vtype);
443	      rq.write_number = decode_write_number(slot, rq);
444	      rq.left_write_number = rq.write_number;
445	
446	      // Update the entry we just pushed
447	      dispatch_q_.back() = rq;
448	
449	      kanata_.comment_insn(rq.pcid.id,
450	                           fmt::format(" lmul:{} sew:{}", rq.lmul, rq.sew));
451	    };
452	
453	    if (cpu_.get_signal("dis_i0_grant"))
454	      do_dispatch(0);
455	    if (cpu_.get_signal("dis_i1_grant"))
456	      do_dispatch(1);
457	  }
458	
459	  void fu_commit()
460	  {
461	    auto do_commit = [&]() {
462	      if (dispatch_q_.empty())
463	        return;
464	      auto rq = dispatch_q_.front();
465	      dispatch_q_.pop_front();
466	
467	      kanata_.stage_insn(rq.pcid.id, "VC", VPU_LANE_ID);
468	
469	      if (write_port_ids_.count(rq.pcid.id))
470	        cmt_q_.push_back(rq);
471	      else
472	        retired_q_.push_back(rq);
473	    };
474	
475	    if (cpu_.get_signal("cmt_i0_grant"))
476	      do_commit();
477	    if (cpu_.get_signal("cmt_i1_grant"))
478	      do_commit();
479	  }
480	
481	  void retire_fu(VectorFU fu, int cnt = 1)
482	  {
483	    for (size_t idx = 0; idx < cmt_q_.size(); ++idx) {
484	      if (cnt <= 0)
485	        break;
486	      auto& rq = cmt_q_[idx];
487	      if (rq.fu != fu)
488	        continue;
489	
490	      if (config_.countdown_vw_labels) {
491	        // andes45 style: emit "VW3", "VW2", "VW1" each write
492	        kanata_.stage_insn(
493	          rq.pcid.id, fmt::format("VW{}", rq.left_write_number), VPU_LANE_ID);
494	        rq.left_write_number -= 1;
495	        cnt -= 1;
496	      } else {
497	        // andes46 style: emit "VW" stage only on first VD write
498	        if (rq.write_number == rq.left_write_number)
499	          kanata_.stage_insn(rq.pcid.id, "VW", VPU_LANE_ID);
500	        // decrease left_write_number until 0, then retire this insn
501	        int decrease = std::min(cnt, rq.left_write_number);
502	        rq.left_write_number -= decrease;
503	        cnt -= decrease;
504	      }
505	
506	      if (rq.left_write_number <= 0) {
507	        retired_q_.push_back(rq);
508	        cmt_q_.erase(cmt_q_.begin() + static_cast<ptrdiff_t>(idx));
509	        --idx;
510	      }
511	    }
512	  }
513	
514	  void fu_wvalid()
515	  {
516	    if (cmt_q_.empty())
517	      return;
518	
519	    // Write to VRF
520	    for (int i = 0; i < static_cast<int>(VectorFU::COUNT_); ++i) {
521	      auto fu = static_cast<VectorFU>(i);
522	      auto name = vfu_name(fu);
523	
524	      if (fu == VectorFU::VLSU && config_.dual_vlsu_ports) {
525	        // andes46: dual VLSU write ports
526	        auto sig0 = fmt::format("{}_vd0_wvalid", name);
527	        auto sig1 = fmt::format("{}_vd1_wvalid", name);
528	        int vd_ports = 0;
529	        vd_ports += static_cast<int>(cpu_.get_signal(sig0));
530	        vd_ports += static_cast<int>(cpu_.get_signal(sig1));
531	        if (vd_ports > 0)
532	          retire_fu(fu, vd_ports);
533	      } else {
534	        auto sig = fmt::format("{}_vd_wvalid", name);
535	        if (cpu_.get_signal(sig))
536	          retire_fu(fu, 1);
537	      }
538	    }
539	
540	    // Write to XRF (scalar result FUs)
541	    // Only 4 RVV instructions (vmv.x.s, vfmv.f.s, vcpop.m, vfirst.m)
542	    // can write to XRF/FRF, handled by these functional units.
543	    static constexpr VectorFU rd_fus[] = {
544	      VectorFU::VSP,
545	      VectorFU::VPERMUT,
546	      VectorFU::VMASK,
547	      VectorFU::VACE,
548	    };
549	    for (auto fu: rd_fus) {
550	      auto sig = fmt::format("{}_srf_wvalid", vfu_name(fu));
551	      if (cpu_.get_signal(sig))
552	        retire_fu(fu, 1);
553	    }
554	  }
555	
556	  void fu_retired()
557	  {
558	    for (auto& rq: retired_q_) {
559	      auto id = rq.pcid.id;
560	      insn_ids_.erase(id);
561	      write_port_ids_.erase(id);
562	      if (!scalar_.has_insn_id(id))
563	        kanata_.retire_insn(id);
564	    }
565	    retired_q_.clear();
566	  }
567	
568	  CPU& cpu_;
569	  KanataLogger& kanata_;
570	  PipelineModeler<CPU>& scalar_;
571	  VpuConfig config_;
572	
573	  std::unordered_set<uint64_t> insn_ids_;
574	  std::unordered_set<uint64_t> write_port_ids_;
575	
576	  std::deque<VpuReq> request_q_;
577	  std::deque<VpuReq> dispatch_q_;
578	  std::vector<VpuReq> cmt_q_;
579	  std::vector<VpuReq> retired_q_;
580	};
581	
582	} // namespace kanata
