#pragma once

#include "kanata_logger.hpp"

#include <fmt/core.h>
#include <spdlog/spdlog.h>

#include <cstdint>

#include <algorithm>
#include <array>
#include <deque>
#include <optional>
#include <string>
#include <string_view>
#include <vector>

namespace kanata {

constexpr int VPU_LANE_ID = 1;

/// Relates a PC address to a Kanata ID.
struct PcId
{
  uint64_t pc;
  uint64_t id;
};

/// Models a single in-order pipeline slot.
/// Port of Python InorderPipe from tools/andes45.py.
class InorderPipe
{
public:
  struct UpdateResult
  {
    std::vector<std::optional<PcId>> stage_start;
    std::vector<std::optional<PcId>> stage_end;
    std::optional<PcId> retire;
  };

  InorderPipe(int stage_num, SequentialIndexMap& id_map)
      : id_map_(id_map),
        stage_status_(stage_num, std::nullopt),
        stage_num_(stage_num)
  {}

  /// Update pipeline state with new per-stage PCs.
  /// stages_pc[i] = nullopt means no instruction at stage i.
  UpdateResult update(const std::vector<std::optional<uint64_t>>& stages_pc)
  {
    UpdateResult res;
    res.stage_start.resize(stage_num_, std::nullopt);
    res.stage_end.resize(stage_num_, std::nullopt);
    std::vector<std::optional<PcId>> new_status(stage_num_, std::nullopt);

    // Process stages 0..N-2
    for (int i = 0; i < stage_num_ - 1; ++i) {
      auto& pcid = stage_status_[i];
      if (!pcid)
        continue;

      if (stages_pc[i] && pcid->pc == *stages_pc[i]) {
        // stall
        new_status[i] = pcid;
      } else if (stages_pc[i + 1] && pcid->pc == *stages_pc[i + 1]) {
        // forward to next stage
        new_status[i + 1] = pcid;
        res.stage_start[i + 1] = pcid;
      } else {
        // killed
        res.stage_end[i] = pcid;
      }
    }

    // Look up ID for first stage
    auto& new_pc = stages_pc[0];
    if (new_pc) {
      if (!stage_status_[0] || *new_pc != stage_status_[0]->pc) {
        id_map_.update(*new_pc);
        auto new_id = id_map_.pop(*new_pc);
        new_status[0] = PcId{*new_pc, new_id};
        res.stage_start[0] = new_status[0];
      }
    }

    // Retire last stage
    if (stage_status_.back()) {
      if (!new_status.back()
          || new_status.back()->id != stage_status_.back()->id)
      {
        res.retire = stage_status_.back();
      }
    }

    stage_status_ = std::move(new_status);
    return res;
  }

private:
  SequentialIndexMap& id_map_;
  std::vector<std::optional<PcId>> stage_status_;
  int stage_num_;
};

/// Signal rule: stage name, pc signal name, condition signal name.
struct SignalRule
{
  std::string stage_name;
  std::string pc_signal;
  std::string cond_signal;
};

/// One pipeline slot (issue lane) configuration.
using PipeSlotConfig = std::vector<SignalRule>;

// ── VPU types ────────────────────────────────────────────────────────────

enum class VectorFU
{
  VALU = 0,
  VLSU,
  VSP,
  VMAC,
  VDIV,
  VFMIS,
  VPERMUT,
  VFDIV,
  VMASK,
  VACE,
  VMAC2,
  COUNT_
};

constexpr std::array<std::string_view, static_cast<int>(VectorFU::COUNT_)>
  kVfuNames = {
    "valu",    "vlsu",  "vsp",   "vmac", "vdiv",  "vfmis",
    "vpermut", "vfdiv", "vmask", "vace", "vmac2",
};

inline std::string_view vfu_name(VectorFU fu)
{
  return kVfuNames[static_cast<int>(fu)];
}

struct VpuConfig
{
  bool dual_vlsu_ports = false;
  bool has_vd_x4 = false;
  bool countdown_vw_labels = true;
};

// ── Pipeline configuration ───────────────────────────────────────────────

/// Full pipeline configuration: stage names, per-slot signal rules, last stage
/// name.
struct PipelineConfig
{
  std::vector<std::string> stage_names;
  std::vector<PipeSlotConfig> slots;
  std::string last_stage_name; // for end_stage_insn on retire
  std::optional<VpuConfig> vpu = std::nullopt;
};

// Forward declare so PipelineModeler can hold a pointer.
template<typename CPU>
class VpuPipelineModeler;

/// Records pipeline events each cycle using CPU signals.
/// Port of Python PipelineModeler from tools/andes45.py.
template<typename CPU>
class PipelineModeler
{
public:
  PipelineModeler(CPU& cpu, KanataLogger& kanata, PipelineConfig config)
      : cpu_(cpu), kanata_(kanata), config_(std::move(config))
  {
    auto num_stages = static_cast<int>(config_.stage_names.size());
    for (size_t i = 0; i < config_.slots.size(); ++i)
      pipes_.emplace_back(num_stages, id_map_);
  }

  void set_vpu(VpuPipelineModeler<CPU>* vpu) { vpu_ = vpu; }

  /// Call once per cycle to record pipeline events.
  void record()
  {
    std::vector<uint64_t> retire_ids;

    // Find the EX stage index (for VPU enqueue)
    int ex_stage_idx = -1;
    if (vpu_) {
      for (size_t i = 0; i < config_.stage_names.size(); ++i) {
        if (config_.stage_names[i] == "EX") {
          ex_stage_idx = static_cast<int>(i);
          break;
        }
      }
    }

    for (size_t slot = 0; slot < config_.slots.size(); ++slot) {
      auto& rules = config_.slots[slot];
      auto& pipe = pipes_[slot];

      // Collect per-stage PCs
      std::vector<std::optional<uint64_t>> stages_pc;
      stages_pc.reserve(rules.size());

      for (auto& rule: rules) {
        auto cond = cpu_.get_signal(rule.cond_signal);
        if (cond)
          stages_pc.push_back(cpu_.get_signal(rule.pc_signal));
        else
          stages_pc.push_back(std::nullopt);
      }

      auto res = pipe.update(stages_pc);

      if (res.retire)
        retire_ids.push_back(res.retire->id);

      // Start a new stage
      for (size_t st = 0; st < config_.stage_names.size(); ++st) {
        auto& pcid = res.stage_start[st];
        if (!pcid)
          continue;
        if (st == 0)
          start_insn(*pcid);
        kanata_.stage_insn(pcid->id, config_.stage_names[st]);

        if (vpu_ && static_cast<int>(st) == ex_stage_idx)
          vpu_->viq_enqueue_ix(static_cast<int>(slot), *pcid);
      }

      // End an old stage (killed)
      for (size_t st = 0; st < config_.stage_names.size(); ++st) {
        auto& pcid = res.stage_end[st];
        if (!pcid)
          continue;
        kanata_.end_stage_insn(pcid->id, config_.stage_names[st]);
        kanata_.flush_insn(pcid->id);
      }
    }

    // VPU pipeline record (before scalar retire, matching Python order)
    if (vpu_)
      vpu_->record();

    // Retire in sorted order
    std::sort(retire_ids.begin(), retire_ids.end());
    for (auto id: retire_ids) {
      kanata_.end_stage_insn(id, config_.last_stage_name);
      end_insn(id);
    }
  }

  bool has_insn_id(uint64_t id) const { return insn_ids_.count(id) != 0; }

private:
  void start_insn(const PcId& pcid)
  {
    kanata_.start_insn(pcid.pc, pcid.id);
    insn_ids_.insert(pcid.id);
  }

  void end_insn(uint64_t id)
  {
    insn_ids_.erase(id);
    if (!vpu_ || !vpu_->has_insn_id(id))
      kanata_.retire_insn(id);
  }

  CPU& cpu_;
  KanataLogger& kanata_;
  PipelineConfig config_;
  SequentialIndexMap id_map_;
  std::vector<InorderPipe> pipes_;
  std::unordered_set<uint64_t> insn_ids_;
  VpuPipelineModeler<CPU>* vpu_ = nullptr;
};

// ── VPU Pipeline Modeler ─────────────────────────────────────────────────

/// Decodes the VLMUL field from VTYPE register.
/// Returns lmul as a float (fractional LMUL supported).
inline double decode_vlmul(uint64_t vtype)
{
  static constexpr double table[] = {
    1.0, 2.0, 4.0, 8.0, /*reserved*/ 1.0, 0.125, 0.25, 0.5,
  };
  return table[vtype & 0x7];
}

/// Decodes the VSEW field from VTYPE register.
inline int decode_vsew(uint64_t vtype)
{
  static constexpr int table[] = {8, 16, 32, 64};
  return table[(vtype >> 3) & 0x3];
}

/// Port of Python VPUPipelineModeler.
// FIXME: The pipeline is not accurate right now, too many corner cases
//        haven't been considered yet. Below are known issues:
//        XXX_vd_wvalid is pulled to 1 for discrete EMUL cycles, and we
//        want to draw VW stages for EMUL times.
//        Therefore, we have to identify all widening and narrowing
//        instructions to calculate the EMUL, which hasn't been done yet.
//        Besides, some RVV instructions always writes to single VRF,
//        independent of LMUL.
template<typename CPU>
class VpuPipelineModeler
{
  struct VpuReq
  {
    VectorFU fu;
    PcId pcid;
    uint32_t instr = 0;
    int lmul = 0;
    int sew = 0;
    int write_number = 0;
    int left_write_number = 0;
  };

public:
  VpuPipelineModeler(CPU& cpu,
                     KanataLogger& kanata,
                     PipelineModeler<CPU>& scalar,
                     VpuConfig config)
      : cpu_(cpu), kanata_(kanata), scalar_(scalar), config_(config)
  {}

  void viq_enqueue_ix(int slot, const PcId& pcid)
  {
    auto vpu_req_valid = cpu_.get_signal("vpu_req_valid");
    if (!(vpu_req_valid & (1u << slot)))
      return;

    auto fu_sig = fmt::format("vpu_req_i{}_fu", slot);
    auto fu = parse_vpu_fu(cpu_.get_signal(fu_sig));

    kanata_.stage_insn(pcid.id, "VQ", VPU_LANE_ID);
    kanata_.comment_insn(pcid.id, vfu_name(fu));

    auto instr_sig = fmt::format("viq_i{}_instr", slot);
    uint32_t instr = static_cast<uint32_t>(cpu_.get_signal(instr_sig));

    request_q_.push_back(VpuReq{fu, pcid, instr, 0, 0, 0, 0});
    start_insn(pcid, instr);
  }

  void record()
  {
    fu_retired();
    fu_wvalid();
    fu_commit();
    fu_dispatch();
  }

  bool has_insn_id(uint64_t id) const { return insn_ids_.count(id) != 0; }

private:
  void start_insn(const PcId& pcid, uint32_t instr)
  {
    insn_ids_.insert(pcid.id);
    if (decode_write_number_not_zero(instr))
      write_port_ids_.insert(pcid.id);
  }

  static VectorFU parse_vpu_fu(uint64_t signal)
  {
    for (int i = 0; i < static_cast<int>(VectorFU::COUNT_); ++i) {
      if (signal & 1u)
        return static_cast<VectorFU>(i);
      signal >>= 1;
    }
    spdlog::warn("VPU: unrecognized FU signal {:#x}", signal);
    return VectorFU::VALU;
  }

  static bool decode_write_number_not_zero(uint32_t instr)
  {
    uint32_t opcode = instr & 0x7F;
    if (opcode == 0b0100111) // OP_STORE
      return false;
    return true;
  }

  int decode_write_number(int slot, VpuReq& rq)
  {
    if (!decode_write_number_not_zero(rq.instr))
      return 0;

    auto vd_wen_sig = fmt::format("i{}_instr_vd_wen", slot);
    auto rd_wen_sig = fmt::format("i{}_rd1_wen", slot);
    auto vd_x2_sig = fmt::format("i{}_vd_x2", slot);
    auto whole_vd_sig = fmt::format("i{}_write_whole_vd", slot);
    auto vd_emul_sig = fmt::format("i{}_vlsu_vd_emul", slot);

    auto vd_wen = cpu_.get_signal(vd_wen_sig);
    auto rd_wen = cpu_.get_signal(rd_wen_sig);
    auto is_wide = cpu_.get_signal(vd_x2_sig);
    auto is_whole_vd = cpu_.get_signal(whole_vd_sig);
    auto vd_emul = cpu_.get_signal(vd_emul_sig);

    if (rd_wen)
      return 1;
    if (!vd_wen)
      return 0;

    if (is_whole_vd) {
      auto n_sig = fmt::format("i{}_whole_vd_num", slot);
      return static_cast<int>(cpu_.get_signal(n_sig));
    }
    if (rq.fu == VectorFU::VLSU)
      return 1 << static_cast<int>(vd_emul);
    if (is_wide)
      return std::max(1, rq.lmul * 2);

    if (config_.has_vd_x4) {
      auto vd_x4_sig = fmt::format("i{}_vd_x4", slot);
      if (cpu_.get_signal(vd_x4_sig))
        return std::max(1, rq.lmul * 4);
    }

    return rq.lmul;
  }

  void fu_dispatch()
  {
    auto do_dispatch = [&](int slot) {
      if (request_q_.empty())
        return;
      auto rq = request_q_.front();
      request_q_.pop_front();
      dispatch_q_.push_back(rq);

      kanata_.stage_insn(rq.pcid.id, "VD", VPU_LANE_ID);

      auto vtype_sig = fmt::format("i{}_vtype", slot);
      auto vtype = cpu_.get_signal(vtype_sig);
      auto lmul_f = decode_vlmul(vtype);
      rq.lmul = std::max(1, static_cast<int>(lmul_f));
      rq.sew = decode_vsew(vtype);
      rq.write_number = decode_write_number(slot, rq);
      rq.left_write_number = rq.write_number;

      // Update the entry we just pushed
      dispatch_q_.back() = rq;

      kanata_.comment_insn(rq.pcid.id,
                           fmt::format(" lmul:{} sew:{}", rq.lmul, rq.sew));
    };

    if (cpu_.get_signal("dis_i0_grant"))
      do_dispatch(0);
    if (cpu_.get_signal("dis_i1_grant"))
      do_dispatch(1);
  }

  void fu_commit()
  {
    auto do_commit = [&]() {
      if (dispatch_q_.empty())
        return;
      auto rq = dispatch_q_.front();
      dispatch_q_.pop_front();

      kanata_.stage_insn(rq.pcid.id, "VC", VPU_LANE_ID);

      if (write_port_ids_.count(rq.pcid.id))
        cmt_q_.push_back(rq);
      else
        retired_q_.push_back(rq);
    };

    if (cpu_.get_signal("cmt_i0_grant"))
      do_commit();
    if (cpu_.get_signal("cmt_i1_grant"))
      do_commit();
  }

  void retire_fu(VectorFU fu, int cnt = 1)
  {
    for (size_t idx = 0; idx < cmt_q_.size(); ++idx) {
      if (cnt <= 0)
        break;
      auto& rq = cmt_q_[idx];
      if (rq.fu != fu)
        continue;

      if (config_.countdown_vw_labels) {
        // andes45 style: emit "VW3", "VW2", "VW1" each write
        kanata_.stage_insn(
          rq.pcid.id, fmt::format("VW{}", rq.left_write_number), VPU_LANE_ID);
        rq.left_write_number -= 1;
        cnt -= 1;
      } else {
        // andes46 style: emit "VW" stage only on first VD write
        if (rq.write_number == rq.left_write_number)
          kanata_.stage_insn(rq.pcid.id, "VW", VPU_LANE_ID);
        // decrease left_write_number until 0, then retire this insn
        int decrease = std::min(cnt, rq.left_write_number);
        rq.left_write_number -= decrease;
        cnt -= decrease;
      }

      if (rq.left_write_number <= 0) {
        retired_q_.push_back(rq);
        cmt_q_.erase(cmt_q_.begin() + static_cast<ptrdiff_t>(idx));
        --idx;
      }
    }
  }

  void fu_wvalid()
  {
    if (cmt_q_.empty())
      return;

    // Write to VRF
    for (int i = 0; i < static_cast<int>(VectorFU::COUNT_); ++i) {
      auto fu = static_cast<VectorFU>(i);
      auto name = vfu_name(fu);

      if (fu == VectorFU::VLSU && config_.dual_vlsu_ports) {
        // andes46: dual VLSU write ports
        auto sig0 = fmt::format("{}_vd0_wvalid", name);
        auto sig1 = fmt::format("{}_vd1_wvalid", name);
        int vd_ports = 0;
        vd_ports += static_cast<int>(cpu_.get_signal(sig0));
        vd_ports += static_cast<int>(cpu_.get_signal(sig1));
        if (vd_ports > 0)
          retire_fu(fu, vd_ports);
      } else {
        auto sig = fmt::format("{}_vd_wvalid", name);
        if (cpu_.get_signal(sig))
          retire_fu(fu, 1);
      }
    }

    // Write to XRF (scalar result FUs)
    // Only 4 RVV instructions (vmv.x.s, vfmv.f.s, vcpop.m, vfirst.m)
    // can write to XRF/FRF, handled by these functional units.
    static constexpr VectorFU rd_fus[] = {
      VectorFU::VSP,
      VectorFU::VPERMUT,
      VectorFU::VMASK,
      VectorFU::VACE,
    };
    for (auto fu: rd_fus) {
      auto sig = fmt::format("{}_srf_wvalid", vfu_name(fu));
      if (cpu_.get_signal(sig))
        retire_fu(fu, 1);
    }
  }

  void fu_retired()
  {
    for (auto& rq: retired_q_) {
      auto id = rq.pcid.id;
      insn_ids_.erase(id);
      write_port_ids_.erase(id);
      if (!scalar_.has_insn_id(id))
        kanata_.retire_insn(id);
    }
    retired_q_.clear();
  }

  CPU& cpu_;
  KanataLogger& kanata_;
  PipelineModeler<CPU>& scalar_;
  VpuConfig config_;

  std::unordered_set<uint64_t> insn_ids_;
  std::unordered_set<uint64_t> write_port_ids_;

  std::deque<VpuReq> request_q_;
  std::deque<VpuReq> dispatch_q_;
  std::vector<VpuReq> cmt_q_;
  std::vector<VpuReq> retired_q_;
};

} // namespace kanata

