9	namespace {
10	
11	constexpr uint64_t START_PC = 0x100;
12	constexpr uint64_t END_PC   = 0x118;
13	constexpr uint64_t OTHER_PC = 0x110;
14	
15	bool contains(const std::string& haystack, const std::string& needle)
16	{
17	  return haystack.find(needle) != std::string::npos;
18	}
19	
20	} // namespace
21	
22	TEST_CASE("no gate: writes pass through unchanged")
23	{
24	  std::stringstream ss;
25	  kanata::KanataLogger log{ss};
26	
27	  log.start_insn(START_PC, /*id=*/1);
28	  log.advance_cycle(1);
29	  log.retire_insn(/*id=*/1);
30	
31	  const auto out = ss.str();
32	  CHECK(contains(out, "I\t1\t1\t0"));
33	  CHECK(contains(out, "L\t1\t0\t0x100"));
34	  CHECK(contains(out, "C\t1"));
35	  CHECK(contains(out, "R\t1\t1\t0"));
36	}
37	
38	TEST_CASE("gate skip=0: records from the first instruction (no warmup)")
39	{
40	  std::stringstream ss;
41	  kanata::KanataLogger log{
42	    ss, kanata::LoopGate{START_PC, END_PC, /*skip=*/0, /*record=*/10}};
43	
44	  // skip=0 means no warmup: the very first insn must be recorded.
45	  log.start_insn(OTHER_PC, /*id=*/1);
46	  log.advance_cycle(1);
47	  log.retire_insn(/*id=*/1);
48	
49	  const auto out = ss.str();
50	  CHECK(contains(out, "I\t1"));
51	  CHECK(contains(out, "C\t1"));
52	  CHECK(contains(out, "R\t1\t1\t0"));
53	}
54	
55	TEST_CASE("gate skip=2: window opens on 3rd end_pc retire")
56	{
57	  std::stringstream ss;
58	  kanata::KanataLogger log{
59	    ss, kanata::LoopGate{START_PC, END_PC, /*skip=*/2, /*record=*/10}};
60	
61	  // Iterations 1 and 2: must NOT be recorded.
62	  for (uint64_t id : {1ULL, 2ULL}) {
63	    log.start_insn(END_PC, id);
64	    log.retire_insn(id);
65	  }
66	  CHECK(ss.str().find("I\t") == std::string::npos);
67	
68	  // Iteration 3: window opens after this end_pc retire.
69	  log.start_insn(END_PC, /*id=*/3);
70	  log.retire_insn(/*id=*/3);
71	
72	  // Iteration 4 body: now recorded.
73	  log.start_insn(OTHER_PC, /*id=*/4);
74	  log.retire_insn(/*id=*/4);
75	
76	  const auto out = ss.str();
77	  CHECK_FALSE(contains(out, "I\t1"));
78	  CHECK_FALSE(contains(out, "I\t2"));
79	  CHECK(contains(out, "I\t4"));
80	}
81	
82	TEST_CASE("gate: flush_insn(end_pc) does NOT advance the iteration counter")
83	{
84	  std::stringstream ss;
85	  kanata::KanataLogger log{
86	    ss, kanata::LoopGate{START_PC, END_PC, /*skip=*/1, /*record=*/10}};
87	
88	  // Speculatively-fetched end_pc that gets flushed (mispredict).
89	  log.start_insn(END_PC, /*id=*/1);
90	  log.flush_insn(/*id=*/1);
