1	/*
2	 * Hot-loop detector plugin.
3	 *
4	 * Detects loops by observing backward TB transitions: when the next
5	 * executed translation block starts at a PC strictly less than the
6	 * last instruction PC of the previously executed TB, we treat that
7	 * pair (header_pc=current_tb_start, tail_pc=last_insn_of_prev_tb) as
8	 * a loop edge and bump its iteration count.
9	 *
10	 * Output (at exit, sorted by iteration count desc):
11	 *   start_pc, end_pc, iterations
12	 *
13	 * Copyright (C) 2026
14	 * License: GNU GPL, version 2 or later.
15	 *   See the COPYING file in the top-level directory.
16	 */
17	#include <inttypes.h>
18	#include <stdlib.h>
19	#include <string.h>
20	#include <stdio.h>
21	#include <glib.h>
22	
23	#include <qemu-plugin.h>
24	
25	QEMU_PLUGIN_EXPORT int qemu_plugin_version = QEMU_PLUGIN_VERSION;
26	
27	static GMutex lock;
28	static GHashTable *loops;        /* key: (start<<1)^end -> LoopEdge* */
29	static GArray *vcpu_state;       /* indexed by cpu_index */
30	static guint64 limit = 50;       /* max rows printed */
31	static guint64 min_iters = 1;    /* rows with count < min_iters are dropped */
32	
33	typedef struct {
34	    uint64_t start_pc;           /* loop header (target of backward branch) */
35	    uint64_t end_pc;             /* tail: last insn pc of preceding TB */
36	    uint64_t count;              /* iterations observed */
37	} LoopEdge;
38	
39	typedef struct {
40	    uint64_t last_tail_pc;       /* PC of last insn of previously executed TB */
41	    bool     valid;
42	} VCPUState;
43	
44	typedef struct {
45	    uint64_t tb_start;
46	    uint64_t tb_last_insn_pc;
47	} TBInfo;
48	
49	static guint loop_hash(gconstpointer p)
50	{
51	    const LoopEdge *e = p;
52	    return (guint)(e->start_pc * 1315423911u ^ e->end_pc);
53	}
54	
55	static gboolean loop_equal(gconstpointer a, gconstpointer b)
56	{
57	    const LoopEdge *x = a, *y = b;
58	    return x->start_pc == y->start_pc && x->end_pc == y->end_pc;
59	}
60	
61	static gint cmp_count_desc(gconstpointer a, gconstpointer b)
62	{
63	    const LoopEdge *x = a, *y = b;
64	    if (x->count == y->count) {
65	        return 0;
66	    }
67	    return x->count > y->count ? -1 : 1;
68	}
69	
70	static VCPUState *get_vcpu_state(unsigned int cpu_index)
71	{
72	    g_mutex_lock(&lock);
73	    while (vcpu_state->len <= cpu_index) {
74	        VCPUState init = { 0, false };
75	        g_array_append_val(vcpu_state, init);
76	    }
77	    VCPUState *st = &g_array_index(vcpu_state, VCPUState, cpu_index);
78	    g_mutex_unlock(&lock);
79	    return st;
80	}
81	
82	static void vcpu_tb_exec(unsigned int cpu_index, void *udata)
83	{
84	    TBInfo *tbi = (TBInfo *)udata;
85	    VCPUState *st = get_vcpu_state(cpu_index);
86	
87	    if (st->valid && tbi->tb_start <= st->last_tail_pc) {
88	        LoopEdge probe = {
89	            .start_pc = tbi->tb_start,
90	            .end_pc   = st->last_tail_pc,
91	        };
92	        g_mutex_lock(&lock);
93	        LoopEdge *e = g_hash_table_lookup(loops, &probe);
94	        if (!e) {
95	            e = g_new0(LoopEdge, 1);
96	            e->start_pc = probe.start_pc;
97	            e->end_pc   = probe.end_pc;
98	            e->count    = 0;
99	            g_hash_table_insert(loops, e, e);
100	        }
101	        e->count++;
102	        g_mutex_unlock(&lock);
103	    }
104	
105	    st->last_tail_pc = tbi->tb_last_insn_pc;
106	    st->valid = true;
107	}
108	
109	static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
110	{
111	    size_t n = qemu_plugin_tb_n_insns(tb);
112	    if (n == 0) {
113	        return;
114	    }
115	    struct qemu_plugin_insn *last = qemu_plugin_tb_get_insn(tb, n - 1);
116	
117	    TBInfo *tbi = g_new0(TBInfo, 1);
118	    tbi->tb_start = qemu_plugin_tb_vaddr(tb);
119	    tbi->tb_last_insn_pc = qemu_plugin_insn_vaddr(last);
120	
121	    qemu_plugin_register_vcpu_tb_exec_cb(tb, vcpu_tb_exec,
122	                                         QEMU_PLUGIN_CB_NO_REGS,
123	                                         (void *)tbi);
124	}
125	
126	static void plugin_exit(qemu_plugin_id_t id, void *p)
127	{
128	    g_autoptr(GString) report = g_string_new("");
129	    GList *vals = g_hash_table_get_values(loops);
130	    vals = g_list_sort(vals, cmp_count_desc);
131	
132	    guint hot = 0;
133	    for (GList *it = vals; it; it = it->next) {
134	        LoopEdge *e = it->data;
135	        if (e->count >= min_iters) {
136	            hot++;
137	        }
138	    }
139	
140	    g_string_append_printf(report,
141	        "hotloops: %u distinct backward edges, %u hot (>= %" PRIu64
142	        " iters), sorted by iterations desc\n",
143	        g_hash_table_size(loops), hot, min_iters);
144	    g_string_append_printf(report, "start_pc, end_pc, iterations\n");
145	
146	    guint64 i = 0;
147	    for (GList *it = vals; it && i < limit; it = it->next) {
148	        LoopEdge *e = it->data;
149	        if (e->count < min_iters) {
150	            continue;
151	        }
152	        g_string_append_printf(report,
153	            "0x%016" PRIx64 ", 0x%016" PRIx64 ", %" PRIu64 "\n",
154	            e->start_pc, e->end_pc, e->count);
155	        i++;
156	    }
157	
158	    qemu_plugin_outs(report->str);
159	
160	    g_list_free(vals);
161	    g_hash_table_destroy(loops);
162	    g_array_free(vcpu_state, TRUE);
163	}
164	
165	QEMU_PLUGIN_EXPORT
166	int qemu_plugin_install(qemu_plugin_id_t id, const qemu_info_t *info,
167	                        int argc, char **argv)
168	{
169	    for (int i = 0; i < argc; i++) {
170	        char *opt = argv[i];
171	        g_auto(GStrv) tok = g_strsplit(opt, "=", 2);
172	        if (g_strcmp0(tok[0], "limit") == 0 && tok[1]) {
173	            limit = g_ascii_strtoull(tok[1], NULL, 0);
174	        } else if (g_strcmp0(tok[0], "min_iters") == 0 && tok[1]) {
175	            min_iters = g_ascii_strtoull(tok[1], NULL, 0);
176	            if (min_iters == 0) {
177	                min_iters = 1;
178	            }
179	        } else {
180	            fprintf(stderr, "hotloops: unknown option: %s\n", opt);
181	            return -1;
182	        }
183	    }
184	
185	    loops = g_hash_table_new_full(loop_hash, loop_equal, NULL, g_free);
186	    vcpu_state = g_array_new(FALSE, TRUE, sizeof(VCPUState));
187	
188	    qemu_plugin_register_vcpu_tb_trans_cb(id, vcpu_tb_trans);
189	    qemu_plugin_register_atexit_cb(id, plugin_exit, NULL);
190	    return 0;
191	}
