template<typename CPU>
class ClarityViewer : public PipelineViewer<CPU>
{
public:
  ClarityViewer(std::string db_path,
                std::unique_ptr<PipelineViewer<CPU>> inner,
                std::unique_ptr<std::stringstream> kanata_buf,
                std::string toml_config)
      : db_path_(std::move(db_path))
      , inner_(std::move(inner))
      , kanata_buf_(std::move(kanata_buf))
      , toml_config_(std::move(toml_config))
